# phytron.proto
# StreamDevice protocol file for Phytron MCC-1 MINI-W-ETH over TCP/IP.
#
# IMPORTANT COMMISSIONING NOTES:
# - The controller uses framed packets with STX=0x02 and ETX=0x03.
# - Verified from capture: TX example = 02 30 58 50 32 30 52 03
# - Verified from capture: RX example = 02 06 31 30 30 03
# - Address handling must be checked during commissioning.
#   Previous non-working setup used address '1'; observed working case used address '0'.
# - The exact command bytes for all operations are NOT fully proven from the provided context.
#   Therefore this file uses the verified frame style and clearly marks placeholders.
# - Replace the command payload bytes below with confirmed MCC-1 command codes if needed.
#
# Macro usage:
#   ADDR = controller address character, typically 0 during commissioning.
#   Example db macro: ADDR=0
#
# Debug strategy:
# - Keep asyn trace enabled in st.cmd.
# - If no reply is seen, verify ADDR first.
# - Then compare transmitted bytes against Wireshark / vendor documentation.

Terminator = "";
ExtraInput = Ignore;
ReplyTimeout = 1000;
ReadTimeout = 1000;
WriteTimeout = 1000;
LockTimeout = 5000;

# Common framing:
#   \x02 <payload> \x03
#
# Verified bytes:
#   \x02 = STX
#   \x03 = ETX
#   The successful trace payload included ASCII bytes: 30 58 50 32 30 52 -> "0XP20R"
# Placeholder bytes:
#   Command mnemonics below are scaffolded around the verified frame style,
#   but must be checked against real MCC-1 protocol documentation / captures.

getPosition {
    # Placeholder command payload in verified framed style.
    # Address handling must be checked here during commissioning.
    # If trace evidence confirms a different read-position command, replace only the payload.
    out "\x02").%(ADDR)s"XP20R\x03";
    # Placeholder response parse:
    # Verified response style begins with STX and ends with ETX.
    # Example observed reply: 02 06 31 30 30 03
    # The integer extraction below is a scaffold and may need adjustment
    # if the controller prepends status/length bytes.
    in "\x02%*c%d\x03";
}

getSpeed {
    # Placeholder framed command for speed readback.
    # STX/ETX are verified; command payload bytes are placeholders and must be validated.
    # Address handling must be checked here during commissioning.
    out "\x02").%(ADDR)s"XV20R\x03";
    in "\x02%*c%d\x03";
}

movePlus {
    # Placeholder framed command for jog/move plus.
    # Command payload bytes are NOT verified from provided evidence.
    # Address handling must be checked here during commissioning.
    out "\x02").%(ADDR)s"XP21R\x03";
}

moveMinus {
    # Placeholder framed command for jog/move minus.
    # Command payload bytes are NOT verified from provided evidence.
    # Address handling must be checked here during commissioning.
    out "\x02").%(ADDR)s"XP22R\x03";
}

stopMotion {
    # Placeholder framed command for motion stop.
    # Command payload bytes are NOT verified from provided evidence.
    # Address handling must be checked here during commissioning.
    out "\x02").%(ADDR)s"XH\x03";
}
